import { inView, animate } from "motion";

/**
 * Check if user prefers reduced motion
 */
export const prefersReducedMotion = (): boolean => {
  if (typeof window === "undefined") return false;
  return window.matchMedia("(prefers-reduced-motion: reduce)").matches;
};

/**
 * Animation directions for fade in
 */
export const fadeDirections = {
  up: { y: [30, 0] },
  down: { y: [-30, 0] },
  left: { x: [30, 0] },
  right: { x: [-30, 0] },
} as const;

export type FadeDirection = keyof typeof fadeDirections;

/**
 * Default animation config
 */
export const defaultAnimationConfig = {
  duration: 0.5,
  easing: [0.4, 0, 0.2, 1] as [number, number, number, number],
};

/**
 * Initialize fade-in animations for elements with .animate-on-scroll class
 */
export const initFadeInAnimations = (): void => {
  if (prefersReducedMotion()) return;

  inView(
    ".animate-on-scroll",
    (element) => {
      const direction = (element.getAttribute("data-direction") || "up") as FadeDirection;
      const delay = parseFloat(element.getAttribute("data-delay") || "0");

      animate(
        element,
        { 
          opacity: [0, 1], 
          ...fadeDirections[direction] 
        },
        { 
          duration: defaultAnimationConfig.duration, 
          easing: defaultAnimationConfig.easing,
          delay,
        }
      );
    },
    { amount: 0.2 }
  );
};

/**
 * Dynamic GSAP loader for CountUp component
 * Only loads GSAP when needed to minimize bundle size
 */
export const loadGSAP = async () => {
  const [gsapModule, scrollTriggerModule] = await Promise.all([
    import("gsap"),
    import("gsap/ScrollTrigger"),
  ]);

  const gsap = gsapModule.default;
  const { ScrollTrigger } = scrollTriggerModule;

  gsap.registerPlugin(ScrollTrigger);

  return { gsap, ScrollTrigger };
};

/**
 * Hero animation config
 */
export const heroAnimationConfig = {
  initial: { opacity: 0, y: 30 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.5, ease: [0.4, 0, 0.2, 1] },
};

/**
 * Card hover animation config
 */
export const cardHoverConfig = {
  scale: 1.02,
  transition: { duration: 0.2 },
};
```

2. Create src/styles/animations.css:

```css
/* Reduced Motion Support */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* Base animation classes */
.animate-on-scroll {
  opacity: 0;
}

/* Stagger animation helper */
.stagger-item {
  --stagger-delay: 0;
  transition-delay: calc(var(--stagger-delay) * 100ms);
}

/* Scroll indicator bounce animation */
@keyframes bounce {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(8px);
  }
}

.animate-bounce-slow {
  animation: bounce 2s ease-in-out infinite;
}

/* Fade in utilities */
.animate-fade-in {
  animation: fadeIn var(--duration-slow) var(--ease-smooth) forwards;
}

@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Slide animations */
.animate-slide-up {
  animation: slideUp var(--duration-slow) var(--ease-out) forwards;
}

@keyframes slideUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.animate-slide-in-left {
  animation: slideInLeft var(--duration-slow) var(--ease-out) forwards;
}

@keyframes slideInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.animate-slide-in-right {
  animation: slideInRight var(--duration-slow) var(--ease-out) forwards;
}

@keyframes slideInRight {
  from {
    opacity: 0;
    transform: translateX(30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

/* Scale on hover for cards */
.hover-scale {
  transition: transform var(--duration-normal) var(--ease-smooth),
              box-shadow var(--duration-normal) var(--ease-smooth);
}

.hover-scale:hover {
  transform: scale(1.02);
  box-shadow: 0 10px 40px -10px rgba(0, 0, 0, 0.15);
}
```

3. Update src/styles/global.css to import animations.css - add this line after the @theme block:

```css
@import "./animations.css";
```

